import pytest

from your_module import partial  # <-- change to the actual import path


def test_partial_happy_path_positional_and_kwargs_merging_order():
    # partial provides:
    # - positional prefix: (1,)
    # - keyword: {"b": 2}
    # call provides:
    # - positional: (3, 4)
    # - keyword: {"b": 20} which should override partial's b=2
    def fn(a, b, c, d):
        return a, b, c, d

    p = partial(fn, 1, b=2)
    assert p(3, 4, b=20) == (1, 20, 3, 4)


